            bp = '(.{%d})(%s)%s(%s)(.{%d})' % (pre, tgt, btw_pat, piece, post)
            gb, db = '\\1\\2\\3\\4\\5', '\\1%s\\3_\\5' % new_piece
            cg, eg = 6, 7
